create extension if not exists pgcrypto;
create type public.person_status as enum ('draft', 'published', 'archived');
create type public.app_role as enum ('admin');
create table public.profiles (id uuid primary key references auth.users(id) on delete cascade, role public.app_role not null default 'admin', created_at timestamptz not null default now());
create table public.categories (id uuid primary key default gen_random_uuid(), name text not null unique, slug text not null unique, created_at timestamptz not null default now());
create table public.tags (id uuid primary key default gen_random_uuid(), name text not null unique, slug text not null unique, created_at timestamptz not null default now());
create table public.people (id uuid primary key default gen_random_uuid(), name text not null, slug text not null unique, description text, status public.person_status not null default 'draft', category_id uuid references public.categories(id) on delete set null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.images (id uuid primary key default gen_random_uuid(), person_id uuid not null references public.people(id) on delete cascade, path text not null unique, alt text, position integer not null default 0, is_cover boolean not null default false, created_at timestamptz not null default now());
create table public.files (id uuid primary key default gen_random_uuid(), person_id uuid not null references public.people(id) on delete cascade, name text not null, path text not null unique, mime_type text not null, size bigint not null check (size >= 0), created_at timestamptz not null default now());
create table public.people_tags (person_id uuid references public.people(id) on delete cascade, tag_id uuid references public.tags(id) on delete cascade, primary key (person_id, tag_id));
create table public.activity_logs (id uuid primary key default gen_random_uuid(), actor_id uuid references auth.users(id) on delete set null, action text not null, entity_type text not null, entity_id uuid, metadata jsonb not null default '{}', created_at timestamptz not null default now());
create index people_search_idx on public.people using gin (to_tsvector('simple', coalesce(name,'') || ' ' || coalesce(description,'')));
create index images_person_idx on public.images(person_id, position); create index files_person_idx on public.files(person_id); create index people_category_idx on public.people(category_id);
create or replace function public.set_updated_at() returns trigger language plpgsql as $$ begin new.updated_at = now(); return new; end; $$;
create trigger people_updated_at before update on public.people for each row execute function public.set_updated_at();
create or replace function public.is_admin() returns boolean language sql stable security definer set search_path = public as $$ select exists(select 1 from public.profiles where id = auth.uid() and role = 'admin') $$;
alter table public.profiles enable row level security; alter table public.categories enable row level security; alter table public.tags enable row level security; alter table public.people enable row level security; alter table public.images enable row level security; alter table public.files enable row level security; alter table public.people_tags enable row level security; alter table public.activity_logs enable row level security;
create policy "public published people" on public.people for select using (status = 'published' or public.is_admin()); create policy "public related images" on public.images for select using (exists(select 1 from public.people p where p.id = person_id and (p.status = 'published' or public.is_admin()))); create policy "public related files" on public.files for select using (exists(select 1 from public.people p where p.id = person_id and (p.status = 'published' or public.is_admin()))); create policy "read categories" on public.categories for select using (true); create policy "read tags" on public.tags for select using (true); create policy "read people tags" on public.people_tags for select using (true); create policy "own profile" on public.profiles for select using (id = auth.uid());
create policy "admin all people" on public.people for all using (public.is_admin()) with check (public.is_admin()); create policy "admin all images" on public.images for all using (public.is_admin()) with check (public.is_admin()); create policy "admin all files" on public.files for all using (public.is_admin()) with check (public.is_admin()); create policy "admin all categories" on public.categories for all using (public.is_admin()) with check (public.is_admin()); create policy "admin all tags" on public.tags for all using (public.is_admin()) with check (public.is_admin()); create policy "admin all people tags" on public.people_tags for all using (public.is_admin()) with check (public.is_admin()); create policy "admin activity" on public.activity_logs for all using (public.is_admin()) with check (public.is_admin());
insert into storage.buckets (id, name, public, file_size_limit, allowed_mime_types) values ('people-images','people-images',true,15728640,array['image/jpeg','image/png','image/webp']), ('people-files','people-files',false,15728640,array['application/pdf','application/zip','application/vnd.rar','application/vnd.openxmlformats-officedocument.wordprocessingml.document','application/vnd.openxmlformats-officedocument.spreadsheetml.sheet','text/plain']) on conflict (id) do nothing;
create policy "admin storage images" on storage.objects for all using (bucket_id = 'people-images' and public.is_admin()) with check (bucket_id = 'people-images' and public.is_admin()); create policy "public images" on storage.objects for select using (bucket_id = 'people-images'); create policy "admin storage files" on storage.objects for all using (bucket_id = 'people-files' and public.is_admin()) with check (bucket_id = 'people-files' and public.is_admin());
